import { Component, signal, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink, ActivatedRoute } from '@angular/router';
import { AttendanceEntry, Level, Member, Role } from '../../core/models';
import { AuthService } from '../../core/services/auth.service';

@Component({
  selector: 'app-member-detail',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './member-detail.component.html',
})
export class MemberDetailComponent {
  private auth = inject(AuthService);
  private id = inject(ActivatedRoute).snapshot.paramMap.get('id') ?? 'u2';

  readonly isCoach = this.auth.isCoach;
  readonly levels: Level[] = ['novice', 'intermediate', 'competitive'];
  readonly roles: Role[] = ['member', 'coach'];

  member = signal<Member>({
    id: 'u2',
    name: 'Alex Rivers',
    email: 'alex@demo',
    role: 'member',
    level: 'intermediate',
  });

  attendance = signal<AttendanceEntry[]>([
    { practiceId: 'p10', startsAt: '2026-07-08T06:00:00Z', status: 'confirmed' },
    { practiceId: 'p11', startsAt: '2026-07-05T06:30:00Z', status: 'confirmed' },
    { practiceId: 'p12', startsAt: '2026-07-01T06:00:00Z', status: 'confirmed' },
  ]);

  // Coach edit state (local for the mockup).
  editLevel = signal<Level>('intermediate');
  editRole = signal<Role>('member');
  saved = signal(false);

  save(): void {
    this.member.update((m) => ({ ...m, level: this.editLevel(), role: this.editRole() }));
    this.saved.set(true);
    // service_agent wires this to ApiService.updateMember.
  }
}
